/**
 * MMS WebSocket Server
 *
 * Bun-native WebSocket server implementation for real-time communication.
 * Creates a separate WebSocket server that runs alongside the HTTP API.
 *
 * Usage:
 *   import { createWebSocketServer } from './server';
 *   const wsServer = createWebSocketServer({ port: 3001 });
 *
 * Connection:
 *   const ws = new WebSocket('ws://localhost:3001/ws');
 *   ws.onopen = () => {
 *     ws.send(JSON.stringify({ type: 'AUTH', data: { token: 'jwt-token' } }));
 *   };
 *
 * @see specs/005-api.md Section 5.14 (WebSocket Events)
 */

import type { ServerWebSocket } from 'bun';
import { logger } from '../../lib/logging/logger';
import { getWebSocketHub, createConnectionId, type WebSocketData } from './hub';

// =============================================================================
// Types
// =============================================================================

export interface WebSocketServerConfig {
  port: number;
  hostname?: string;
  path?: string;
}

/** Bun server with WebSocket support */
type BunServer = ReturnType<typeof Bun.serve<WebSocketData>>;

export interface WebSocketServerInstance {
  server: BunServer;
  stop: () => void;
}

// =============================================================================
// Server Factory
// =============================================================================

/**
 * Create a Bun WebSocket server
 */
export function createWebSocketServer(config: WebSocketServerConfig): WebSocketServerInstance {
  const { port, hostname = '0.0.0.0', path = '/ws' } = config;
  const hub = getWebSocketHub();
  const log = logger.child({ service: 'websocket-server' });

  const server = Bun.serve<WebSocketData>({
    port,
    hostname,

    fetch(req, server) {
      const url = new URL(req.url);

      // Health check endpoint
      if (url.pathname === '/health') {
        const stats = hub.getStats();
        return new Response(
          JSON.stringify({
            status: 'healthy',
            timestamp: new Date().toISOString(),
            websocket: stats,
          }),
          { headers: { 'Content-Type': 'application/json' } }
        );
      }

      // WebSocket upgrade
      if (url.pathname === path) {
        const connectionId = createConnectionId();
        const ipAddress = req.headers.get('x-forwarded-for') ??
                         req.headers.get('x-real-ip') ??
                         server.requestIP(req)?.address;
        const userAgent = req.headers.get('user-agent') ?? undefined;

        const upgraded = server.upgrade(req, {
          data: {
            connectionId,
            ipAddress: ipAddress ?? undefined,
            userAgent,
          },
        });

        if (!upgraded) {
          return new Response('WebSocket upgrade failed', { status: 500 });
        }

        return undefined;
      }

      // 404 for other routes
      return new Response('Not Found', { status: 404 });
    },

