/**
 * MMS Workers - Central Exports
 *
 * BullMQ worker infrastructure for background job processing.
 * Each worker processes jobs from its designated queue with
 * consistent error handling, tracing, and metrics.
 *
 * Worker Types:
 * - ingestion: CSV file processing and mileage data import
 * - tactical_scheduler: PM scheduling within 12-week horizon
 * - strategic_planner: Long-term (10-year) PM planning
 * - optimizer: Run assignment optimization (C++ CP-SAT or TS fallback)
 * - manhour_leveling: Workload balancing across periods
 * - drift_monitor: Baseline comparison and drift detection
 * - notification: Email and alert sending
 * - report: PDF/Excel report generation
 *
 * @see specs/004-domain-services.md Section 4.8
 * @see specs/002-architecture.md Section 2.4 - Worker Layer
 */

import { Worker, type WorkerOptions, type Job } from 'bullmq';
import { logger } from '../lib/logging/logger';
import { QUEUE_NAMES, type QueueName, type JobData } from '../lib/queue';
import { withSpan } from '../lib/tracing';
import { toMmsError, QueueError } from '../lib/errors';
import { workerMetrics } from '../lib/metrics';

// =============================================================================
// Worker Configuration
// =============================================================================

/**
 * Default worker options applied to all workers
 */
export const DEFAULT_WORKER_OPTIONS: Partial<WorkerOptions> = {
  concurrency: 1,
  autorun: true,
  lockDuration: 30000, // 30 seconds
  lockRenewTime: 15000, // 15 seconds
  limiter: undefined, // No rate limiting by default
};

/**
 * Worker-specific configurations
 */
export const WORKER_CONFIGS: Record<
  keyof typeof QUEUE_NAMES,
  { concurrency: number; lockDuration: number; description: string }
> = {
  INGESTION: {
    concurrency: 1, // Sequential to avoid race conditions
    lockDuration: 60000, // 1 minute for file processing
    description: 'CSV file processing and mileage data import',
  },
  TACTICAL_SCHEDULER: {
    concurrency: 1, // Single scheduler to maintain consistency
    lockDuration: 300000, // 5 minutes for scheduling
    description: 'PM scheduling within 12-week horizon',
  },
  STRATEGIC_PLANNER: {
    concurrency: 1, // Single planner for GA optimization
    lockDuration: 600000, // 10 minutes for long-term planning
    description: 'Long-term (10-year) PM planning with genetic algorithm',
  },
  OPTIMIZER: {
    concurrency: 2, // Can run multiple optimizations in parallel
    lockDuration: 60000, // 1 minute per optimization
    description: 'Run assignment optimization (C++ CP-SAT or TS fallback)',
  },
  MANHOUR_LEVELING: {
    concurrency: 1, // Sequential processing
    lockDuration: 120000, // 2 minutes
    description: 'Workload balancing across periods',
  },
  DRIFT_MONITOR: {
    concurrency: 2, // Can analyze multiple baselines
    lockDuration: 60000, // 1 minute
    description: 'Baseline comparison and drift detection',
  },
  NOTIFICATION: {
    concurrency: 5, // High concurrency for notifications
    lockDuration: 30000, // 30 seconds
    description: 'Email and alert sending',
  },
  REPORT: {
    concurrency: 2, // PDF/Excel generation
    lockDuration: 120000, // 2 minutes for report generation
    description: 'PDF/Excel report generation',
  },
  MAXIMO_SYNC: {
    concurrency: 1, // Sequential to avoid race conditions with Maximo
    lockDuration: 300000, // 5 minutes for sync operations
    description: 'Bidirectional sync with Maximo work order system',
  },
};

// =============================================================================
// Redis Configuration
// =============================================================================

