/**
 * MMS Worker Broadcast Utilities
 *
 * Provides functions for workers to emit events to the WebSocket hub
 * for real-time client updates. Workers call these functions to broadcast
 * job progress, completion, and domain events to connected clients.
 *
 * Usage:
 *   import { broadcastOptimizerProgress, broadcastOptimizerComplete } from './broadcast';
 *   await broadcastOptimizerProgress({ jobId, percent, ... });
 *
 * IMPORTANT: Workers run in a separate process from the HTTP server.
 * These functions access the shared singleton WebSocket hub when running
 * in the same process (dev mode) or send HTTP requests to the WebSocket
 * server when running in separate processes (production).
 *
 * @see specs/005-api.md Section 5.14 (WebSocket Events)
 */

import { logger } from '../lib/logging/logger';
import type {
  OptimizerProgressData,
  OptimizerCompleteData,
  DriftUpdatedData,
  ManhourUpdatedData,
} from '../api/websocket/types';

const log = logger.child({ module: 'worker-broadcast' });

// =============================================================================
// WebSocket Hub Access
// =============================================================================

/**
 * Get the WebSocket hub instance.
 *
 * Uses dynamic import to avoid circular dependencies and allow
 * the hub to be initialized lazily.
 */
async function getHub() {
  try {
    const { getWebSocketHub } = await import('../api/websocket/hub');
    return getWebSocketHub();
  } catch (error) {
    log.warn({ error }, 'WebSocket hub not available - broadcasts will be skipped');
    return null;
  }
}

// =============================================================================
// Optimizer Events
// =============================================================================

/**
 * Broadcast optimizer job progress to connected clients.
 *
 * Called during optimization to show real-time progress indicators.
 * Clients subscribed to the 'optimizer' room will receive these events.
 *
 * @param data - Progress data including job ID, percent complete, current objective
 */
export async function broadcastOptimizerProgress(data: OptimizerProgressData): Promise<void> {
  const hub = await getHub();
  if (!hub) return;

  try {
    hub.broadcastOptimizerProgress(data);
    log.debug({ jobId: data.jobId, percent: data.percent }, 'Broadcast optimizer progress');
  } catch (error) {
    log.error({ error, jobId: data.jobId }, 'Failed to broadcast optimizer progress');
  }
}

/**
 * Broadcast optimizer job completion to connected clients.
 *
 * Called when optimization finishes (success or failure) to notify
 * clients that results are available.
 *
 * @param data - Completion data including job ID, status, solve time
 */
export async function broadcastOptimizerComplete(data: OptimizerCompleteData): Promise<void> {
  const hub = await getHub();
  if (!hub) return;

  try {
    hub.broadcastOptimizerComplete(data);
    log.info({ jobId: data.jobId, status: data.status }, 'Broadcast optimizer complete');
  } catch (error) {
    log.error({ error, jobId: data.jobId }, 'Failed to broadcast optimizer complete');
  }
}

// =============================================================================
// Drift Monitor Events
// =============================================================================

/**
 * Broadcast drift analysis update to connected clients.
 *
 * Called when drift monitor detects changes in schedule adherence
 * relative to a baseline. Clients displaying drift overlays will update.
 *
 * @param data - Drift data including baseline ID, train info, drift days
 */
export async function broadcastDriftUpdated(data: DriftUpdatedData): Promise<void> {
  const hub = await getHub();
  if (!hub) return;

  try {
    hub.broadcastDriftUpdated(data);
    log.debug({ baselineId: data.baselineId, trainId: data.trainId }, 'Broadcast drift updated');
  } catch (error) {
    log.error({ error, baselineId: data.baselineId }, 'Failed to broadcast drift updated');
  }
}

// =============================================================================
// Manhour Leveling Events
// =============================================================================

/**
 * Broadcast manhour workload update to connected clients.
 *
 * Called when manhour leveling adjusts workload projections.
 * Clients displaying manhour overlays will update.
 *
 * @param data - Manhour data including depot, period, utilization
 */
export async function broadcastManhourUpdated(data: ManhourUpdatedData): Promise<void> {
  const hub = await getHub();
  if (!hub) return;

  try {
    hub.broadcastManhourUpdated(data);
