// =============================================================================

/**
 * Process optimizer job
 *
 * Fetches required data, builds input, runs optimization,
 * and stores/broadcasts results.
 */
export async function processOptimizerJob(
  context: WorkerJobContext<OptimizerJobData>
): Promise<OptimizerFullResult> {
  return withSpan('worker.optimizer.process', async (span) => {
    const { id, data } = context;
    const { date, fleetId, constraints, timeoutMs } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('date', date);
    span.setAttribute('fleetId', fleetId);
    span.setAttribute('hasConstraints', !!constraints);

    log.info({ jobId: id, date, fleetId }, 'Processing optimizer job');

    // Update progress: fetching data
    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 10 });
    await context.log('Fetching trains and routes from database');

    // Build optimizer input
    const input = await buildOptimizerInput(date, fleetId, constraints, timeoutMs);

    // Update progress: optimizing
    await context.updateProgress({ stage: 'OPTIMIZING', percent: 30 });
    await context.log(`Starting optimization for ${input.trains.length} trains, ${input.routes.length} routes`);

    // Run optimization with progress callback
    const result = await runAssignmentOptimizer.optimize(input, async (progress) => {
      await context.updateProgress({
        stage: 'OPTIMIZING',
        percent: 30 + Math.floor(progress.percent * 0.6),
        objective: progress.currentObjective,
        feasible: progress.feasible,
      });
    });

    // Update progress: storing results
    await context.updateProgress({ stage: 'STORING_RESULTS', percent: 95 });
    await context.log(`Optimization complete: ${result.summary.trainsAssigned} trains assigned`);

    // Store run assignments to database for historical analysis
    await storeOptimizationResults(date, input.requestId, result);

    // Broadcast via WebSocket (to be implemented when WebSocket hub exists)
    // await broadcastOptimizationComplete(date, fleetId, result);

    // Update metrics
    optimizerMetrics.trainsAssigned
      .labels(fleetId)
      .set(result.summary.trainsAssigned);

    log.info(
      {
        jobId: id,
        status: result.status,
        trainsAssigned: result.summary.trainsAssigned,
        trainsUnassigned: result.summary.trainsUnassigned,
        solveTimeMs: result.solveTimeMs,
      },
      'Optimizer job complete'
    );

    return result;
  });
}

/**
 * Build optimizer input from database
 */
async function buildOptimizerInput(
  date: string,
  fleetId: string,
  constraints?: OptimizerJobData['constraints'],
  timeoutMs?: number
): Promise<OptimizerFullInput> {
  const requestId = crypto.randomUUID();

  // Fetch fleet info
  const fleet = await db.query.fleets.findFirst({
    where: eq(fleets.id, fleetId),
  });

  if (!fleet) {
    throw new ValidationError('Fleet not found', {
      field: 'fleetId',
      context: { fleetId },
    });
  }

  // Fetch trains for this fleet
  const trainRecords = await db.query.trains.findMany({
    where: eq(trains.fleetId, fleetId),
  });

