/**
 * MMS Optimizer Worker Processor
 *
 * BullMQ job processor for run assignment optimization.
 * Handles job lifecycle, progress reporting, and result storage.
 *
 * Job Flow:
 * 1. Receive OptimizerJobData from queue
 * 2. Fetch trains, routes, constraints from database
 * 3. Build OptimizerFullInput
 * 4. Run optimizer (C++ or fallback)
 * 5. Store results and broadcast via WebSocket
 *
 * @see specs/002-architecture.md Section 2.2.4
 * @see specs/004-domain-services.md Section 4.3
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { db } from '../../lib/db/connection';
import { ValidationError } from '../../lib/errors';
import { optimizerMetrics } from '../../lib/metrics';
import { type WorkerJobContext } from '../index';
import { type OptimizerJobData } from '../../lib/queue';
import {
  runAssignmentOptimizer,
  type OptimizerFullInput,
  type OptimizerFullResult,
  type OptimizerTrainInput,
  type OptimizerRouteInput,
  type HardConstraint,
  type SoftConstraint,
  type UnavailabilityEvent,
  type ServiceDemand,
  DEFAULT_OPTIMIZER_CONFIG,
} from '../../optimizer';

// Import database schemas
import { trains, fleets, unavailabilityEvents, serviceDemand, runAssignments } from '../../lib/db/schema';
import { eq, and, sql } from 'drizzle-orm';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'optimizer' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process optimizer job
 *
 * Fetches required data, builds input, runs optimization,
 * and stores/broadcasts results.
 */
export async function processOptimizerJob(
  context: WorkerJobContext<OptimizerJobData>
): Promise<OptimizerFullResult> {
  return withSpan('worker.optimizer.process', async (span) => {
    const { id, data } = context;
    const { date, fleetId, constraints, timeoutMs } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('date', date);
    span.setAttribute('fleetId', fleetId);
    span.setAttribute('hasConstraints', !!constraints);

    log.info({ jobId: id, date, fleetId }, 'Processing optimizer job');

    // Update progress: fetching data
    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 10 });
    await context.log('Fetching trains and routes from database');

    // Build optimizer input
    const input = await buildOptimizerInput(date, fleetId, constraints, timeoutMs);

    // Update progress: optimizing
    await context.updateProgress({ stage: 'OPTIMIZING', percent: 30 });
    await context.log(`Starting optimization for ${input.trains.length} trains, ${input.routes.length} routes`);

    // Run optimization with progress callback
    const result = await runAssignmentOptimizer.optimize(input, async (progress) => {
      await context.updateProgress({
        stage: 'OPTIMIZING',
        percent: 30 + Math.floor(progress.percent * 0.6),
        objective: progress.currentObjective,
        feasible: progress.feasible,
      });
    });

    // Update progress: storing results
    await context.updateProgress({ stage: 'STORING_RESULTS', percent: 95 });
    await context.log(`Optimization complete: ${result.summary.trainsAssigned} trains assigned`);

    // Store run assignments to database for historical analysis
    await storeOptimizationResults(date, input.requestId, result);

    // Broadcast via WebSocket (to be implemented when WebSocket hub exists)
    // await broadcastOptimizationComplete(date, fleetId, result);

    // Update metrics
    optimizerMetrics.trainsAssigned
      .labels(fleetId)
      .set(result.summary.trainsAssigned);

    log.info(
      {
        jobId: id,
        status: result.status,
        trainsAssigned: result.summary.trainsAssigned,
        trainsUnassigned: result.summary.trainsUnassigned,
        solveTimeMs: result.solveTimeMs,
      },
      'Optimizer job complete'
    );

    return result;
  });
}

/**
 * Build optimizer input from database
 */
async function buildOptimizerInput(
  date: string,
  fleetId: string,
  constraints?: OptimizerJobData['constraints'],
  timeoutMs?: number
): Promise<OptimizerFullInput> {
  const requestId = crypto.randomUUID();

  // Fetch fleet info
  const fleet = await db.query.fleets.findFirst({
    where: eq(fleets.id, fleetId),
  });

  if (!fleet) {
    throw new ValidationError('Fleet not found', {
      field: 'fleetId',
      context: { fleetId },
    });
  }

  // Fetch trains for this fleet
  const trainRecords = await db.query.trains.findMany({
    where: eq(trains.fleetId, fleetId),
  });

  if (trainRecords.length === 0) {
    throw new ValidationError('No trains found for fleet', {
      field: 'fleetId',
      context: { fleetId },
    });
  }

  // Calculate fleet average mileage for target calculation
  const totalMileage = trainRecords.reduce(
    (sum, t) => sum + (t.currentMileageKm || 0),
    0
  );
  const avgMileage = Math.round(totalMileage / trainRecords.length);

  // Transform trains
  const baseDepotId = fleet.baseDepotId || '';
  const optimizerTrains: OptimizerTrainInput[] = trainRecords.map((t) => ({
    id: t.id,
    trainNumber: t.trainNumber,
    fleetId: t.fleetId,
    currentMileageKm: t.currentMileageKm || 0,
    targetMileageKm: t.targetMileageKm || avgMileage,
    fitnessStatus: t.fitnessStatus as 'FIT' | 'RESTRICTED' | 'GROUNDED',
    restrictions: [],
    homeDepotId: baseDepotId,
    currentDepotId: baseDepotId,
  }));

  // Fetch routes
  const routeRecords = await db.query.routes.findMany();

  // Filter routes compatible with this fleet
  const compatibleRoutes = routeRecords.filter((r) => {
    if (!r.allowedFleetIds || r.allowedFleetIds.length === 0) {
      return true; // No restriction means all fleets allowed
    }
    return r.allowedFleetIds.includes(fleetId);
  });

  // Transform routes
  const optimizerRoutes: OptimizerRouteInput[] = compatibleRoutes.map((r) => ({
    id: r.id,
    routeCode: r.routeCode,
    expectedKmPerDay: r.expectedKmPerDay || 250,
    requiredTrains: r.requiredTrains || 1,
    allowedFleetIds: r.allowedFleetIds || [],
    restrictions: [],
  }));

  // Build hard constraints
  const hardConstraints: HardConstraint[] = [];

  // Add unavailable trains from constraints
  if (constraints?.unavailableTrains) {
    for (const trainId of constraints.unavailableTrains) {
      hardConstraints.push({
        type: 'UNAVAILABLE',
        trainId,
        description: 'Train marked as unavailable for this assignment',
      });
    }
  }

  // Fetch active unavailability events
  const unavailabilityRecords = await db.query.unavailabilityEvents.findMany({
    where: and(
      eq(unavailabilityEvents.status, 'ACTIVE'),
    ),
  });

  const unavailabilityEventsList: UnavailabilityEvent[] = unavailabilityRecords
    .filter((e) => optimizerTrains.some((t) => t.id === e.trainId))
    .map((e) => ({
      trainId: e.trainId,
      eventType: e.eventType as UnavailabilityEvent['eventType'],
      status: e.status as 'ACTIVE' | 'RESOLVED',
      blocksRunAssignment: e.restrictionLevel === 'GROUNDED',
      description: e.description || undefined,
      externalReference: e.externalReference || undefined,
    }));

  // Build soft constraints for mileage balancing
  const softConstraints: SoftConstraint[] = optimizerTrains.map((t) => ({
    type: 'MILEAGE_BALANCE' as const,
    trainId: t.id,
    penaltyWeight: 100,
    description: `Mileage balance for ${t.trainNumber}`,
  }));

  // Fetch service demand
  const demandRecords = await db.query.serviceDemand.findMany({
    where: eq(serviceDemand.fleetId, fleetId),
  });

  const serviceDemandList: ServiceDemand[] = demandRecords.map((d) => ({
    fleetId: d.fleetId,
    minTrainsRequired: d.minTrainsRequired,
    dayType: d.dayType as ServiceDemand['dayType'],
  }));

  // Build config
  const config = {
    ...DEFAULT_OPTIMIZER_CONFIG,
    maxSolveTimeSeconds: timeoutMs ? Math.floor(timeoutMs / 1000) : 30,
  };

  return {
    requestId,
    assignmentDate: date,
    config,
    trains: optimizerTrains,
    routes: optimizerRoutes,
    hardConstraints,
    softConstraints,
    unavailabilityEvents: unavailabilityEventsList,
    serviceDemand: serviceDemandList,
  };
}

// =============================================================================
// Result Storage
// =============================================================================

/**
 * Store optimization results to the run_assignments table
 *
 * Persists all train-to-route assignments for historical analysis.
 * Used by RouteUtilizationService to determine typical route assignments
 * for trains, enabling more accurate mileage projections.
 *
 * @param assignmentDate - Date of the assignments
 * @param requestId - UUID grouping this optimization run
 * @param result - Optimizer result containing assignments
 */
async function storeOptimizationResults(
  assignmentDate: string,
  requestId: string,
  result: OptimizerFullResult
): Promise<void> {
  return withSpan('worker.optimizer.storeResults', async (span) => {
    span.setAttribute('requestId', requestId);
    span.setAttribute('assignmentDate', assignmentDate);
    span.setAttribute('assignmentCount', result.assignments.length);
    span.setAttribute('optimizerStatus', result.status);

    if (result.assignments.length === 0) {
      log.info({ requestId, assignmentDate }, 'No assignments to store');
      return;
    }

    try {
      // Prepare batch insert values
      const values = result.assignments.map((assignment) => ({
        trainId: assignment.trainId,
        routeId: assignment.routeId,
        assignmentDate,
        requestId,
        optimizerStatus: result.status as 'OPTIMAL' | 'FEASIBLE' | 'FALLBACK' | 'INFEASIBLE',
        score: assignment.score.toFixed(4),
        explanation: JSON.stringify(assignment.explanation),
      }));

      // Use upsert to handle re-runs for the same date
      // On conflict (trainId + assignmentDate), update the assignment
      await db
        .insert(runAssignments)
        .values(values)
        .onConflictDoUpdate({
          target: [runAssignments.trainId, runAssignments.assignmentDate],
          set: {
            routeId: sql`EXCLUDED.route_id`,
            requestId: sql`EXCLUDED.request_id`,
            optimizerStatus: sql`EXCLUDED.optimizer_status`,
            score: sql`EXCLUDED.score`,
            explanation: sql`EXCLUDED.explanation`,
          },
        });

      log.info(
        {
          requestId,
          assignmentDate,
          storedCount: result.assignments.length,
          status: result.status,
        },
        'Run assignments stored successfully'
      );
    } catch (error) {
      log.error(
        {
          requestId,
          assignmentDate,
          error: error instanceof Error ? error.message : String(error),
        },
        'Failed to store run assignments'
      );
      // Don't throw - storage failure shouldn't fail the job
      // The optimization itself succeeded
    }
  });
}

