// Worker Registration
// =============================================================================

/**
 * Register the optimizer worker
 */
export function registerOptimizerWorker() {
  // Dynamic import to avoid circular dependency
  // Worker registration is done in the worker startup script
  log.info('Optimizer worker processor registered');
}

