// Update progress: identifying imbalances
await context.updateProgress({ stage: 'ANALYZING', percent: 45 });
await context.log('Identifying overloaded and underutilized periods');

// Update progress: applying strategies
await context.updateProgress({ stage: 'LEVELING', percent: 60 });
await context.log('Applying leveling strategies');

// Run projection and leveling
// The service handles:
// - Loading PM schedule within horizon
// - Calculating raw man-hour requirements
// - Loading depot capacity configurations
// - Identifying imbalances (overload >100%, underutilized <70%)
// - Applying strategies in priority order
// - Generating proposed adjustments
const result = await levelingService.generateProjections({
  horizonWeeks,
  depotIds: depotId ? [depotId] : undefined,
  granularity: 'WEEKLY',
});

// Update progress: finalizing
await context.updateProgress({ stage: 'FINALIZING', percent: 90 });

// Calculate summary metrics
const { original, leveled, adjustments, improvement } = result;
const overloadedBefore = original.projections.filter((p) => p.isOverloaded).length;
const overloadedAfter = leveled.projections.filter((p) => p.isOverloaded).length;
const underutilizedBefore = original.projections.filter((p) => p.isUnderutilized).length;
const underutilizedAfter = leveled.projections.filter((p) => p.isUnderutilized).length;

log.info(
  {
    jobId: id,
    projectionRunId: result.projectionRunId,
    horizonWeeks: result.horizonWeeks,
    depots: result.depotIds.length,
    overloadedBefore,
    overloadedAfter,
    underutilizedBefore,
    underutilizedAfter,
    adjustments: adjustments.length,
    utilizationDelta: improvement.utilizationDelta,
    totalCostImpact: improvement.totalCostImpact,
  },
  'Man-hour leveling complete'
);

await context.log(
  `Leveling complete: ${overloadedBefore} → ${overloadedAfter} overloaded periods, ` +
    `${underutilizedBefore} → ${underutilizedAfter} underutilized periods`
);

await context.log(
  `Generated ${adjustments.length} adjustments, ` +
    `utilization improved by ${improvement.utilizationDelta.toFixed(1)}%`
);

// Log proposed adjustments by type
const adjustmentsByType: Record<string, number> = {};
for (const adj of adjustments) {
  adjustmentsByType[adj.type] = (adjustmentsByType[adj.type] ?? 0) + 1;
}

if (Object.keys(adjustmentsByType).length > 0) {
  const typeSummary = Object.entries(adjustmentsByType)
    .map(([type, count]) => `${type}: ${count}`)
    .join(', ');
  await context.log(`Adjustment breakdown: ${typeSummary}`);
}

// Log high-risk adjustments that need attention
const highRiskAdjustments = adjustments.filter((a) => a.riskLevel === 'MEDIUM' || a.riskLevel === 'HIGH');
if (highRiskAdjustments.length > 0) {
  log.warn(
    {
      jobId: id,
      count: highRiskAdjustments.length,
    },
    'High-risk adjustments require review'
  );
  await context.log(`⚠️ ${highRiskAdjustments.length} adjustments require supervisor review`);

  for (const adj of highRiskAdjustments.slice(0, 3)) {
    await context.log(`  - ${adj.type}: ${adj.reason}`);
  }
}

// Log manual review items
const manualReview = adjustments.filter((a) => a.type === 'MANUAL_REVIEW');
if (manualReview.length > 0) {
  log.warn(
    {
      jobId: id,
      count: manualReview.length,
    },
    'Unresolvable overloads flagged for manual review'
  );
  await context.log(`🔴 ${manualReview.length} periods flagged for MANUAL_REVIEW - capacity insufficient`);

