/**
 * MMS Tactical Scheduler Worker Processor
 *
 * BullMQ job processor for tactical PM scheduling within 12-week horizon.
 * Handles PM scheduling respecting constraints:
 * - Compliance windows (mileage OR time triggers)
 * - PM hierarchy (C4 satisfies C1/C2/C3)
 * - Track capabilities and availability
 * - Material constraints (hard 14 days, soft 90 days)
 * - Maximo lock status validation
 * - Service demand minimums
 *
 * Job Flow:
 * 1. Receive TacticalSchedulerJobData from queue
 * 2. Load fleet state and PM types
 * 3. Calculate compliance windows for due PMs
 * 4. Run tactical scheduling via PMSchedulerService
 * 5. Validate against service demand
 * 6. Store results and broadcast via WebSocket
 *
 * @see specs/004-domain-services.md Section 4.4
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type TacticalSchedulerJobData } from '../../lib/queue';
import { getPMSchedulerService, type SchedulingResult } from '../../services';
import { broadcastSchedulerProgress, broadcastSchedulerComplete } from '../broadcast';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'tactical-scheduler' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process tactical scheduler job
 *
 * Runs PM scheduling within 12-week horizon, respecting all constraints.
 * Returns scheduling results including scheduled, deferred, and blocked PMs.
 */
export async function processTacticalSchedulerJob(
  context: WorkerJobContext<TacticalSchedulerJobData>
): Promise<SchedulingResult> {
  return withSpan('worker.tactical_scheduler.process', async (span) => {
    const { id, data } = context;
    const { fleetId, trainIds, horizonWeeks = 12, dryRun = false } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('horizonWeeks', horizonWeeks);
    span.setAttribute('dryRun', dryRun);
    if (fleetId) {
      span.setAttribute('fleetId', fleetId);
    }
    if (trainIds) {
      span.setAttribute('trainCount', trainIds.length);
    }

    log.info(
      {
        jobId: id,
        fleetId: fleetId ?? 'all',
        trainCount: trainIds?.length ?? 'all',
        horizonWeeks,
        dryRun,
      },
      'Processing tactical scheduler job'
    );

    // Update progress: initializing
    await context.updateProgress({ stage: 'INITIALIZING', percent: 5 });
    await context.log('Initializing tactical scheduling');

    // Get PM scheduler service
    const pmSchedulerService = getPMSchedulerService();

    // Update progress: loading data
    await context.updateProgress({ stage: 'LOADING_DATA', percent: 15 });
    await context.log(`Loading fleet data for ${horizonWeeks}-week horizon`);

    // Update progress: calculating compliance windows
    await context.updateProgress({ stage: 'CALCULATING_COMPLIANCE', percent: 30 });
    await context.log('Calculating compliance windows for due PMs');

    // Run tactical scheduling
    // The service handles:
    // - Finding PMs due within horizon
    // - Calculating compliance windows
    // - Checking material availability
    // - Allocating tracks based on capabilities
    // - Validating against service demand
    // - Generating explanations for decisions
    await context.updateProgress({ stage: 'SCHEDULING', percent: 50 });
    await context.log(`Running tactical scheduling${dryRun ? ' (DRY RUN)' : ''}`);

    const result = await pmSchedulerService.runTacticalSchedule({
      fleetId,
      horizonWeeks,
      dryRun,
      respectLocks: true, // Always respect Maximo locks
    });

    // Update progress: validating
    await context.updateProgress({ stage: 'VALIDATING', percent: 80 });

    // Log summary - using the separate arrays in SchedulingResult
    const scheduledCount = result.scheduled.length;
    const deferredCount = result.deferred.length;
    const blockedCount = result.blocked.length;

    log.info(
      {
        jobId: id,
        scheduled: scheduledCount,
        deferred: deferredCount,
        blocked: blockedCount,
        materialWarnings: result.materialWarnings.length,
        summary: result.summary,
        dryRun,
      },
      'Tactical scheduling complete'
    );

    await context.log(
      `Scheduling complete: ${scheduledCount} scheduled, ${deferredCount} deferred, ${blockedCount} blocked`
    );

    // Log material warnings (structure: trainId, trainNumber, pmCode, targetDate, warnings[])
    if (result.materialWarnings.length > 0) {
      await context.log(`Material warnings: ${result.materialWarnings.length} trains with material issues`);

      for (const warning of result.materialWarnings.slice(0, 5)) {
        // Each warning has an array of MaterialAvailability items
        const shortfalls = warning.warnings.filter((w) => !w.isAvailable);
        log.warn(
          {
            jobId: id,
            trainId: warning.trainId,
            trainNumber: warning.trainNumber,
            pmCode: warning.pmCode,
            shortfallCount: shortfalls.length,
          },
          `Material warning: ${warning.trainNumber} ${warning.pmCode}`
        );
      }

      if (result.materialWarnings.length > 5) {
        await context.log(`... and ${result.materialWarnings.length - 5} more material warnings`);
      }
    }

    // Log blocked PMs
    if (result.blocked.length > 0) {
      await context.log(`Blocked PMs require attention:`);

      for (const blocked of result.blocked.slice(0, 5)) {
        log.warn(
          {
            jobId: id,
            trainNumber: blocked.trainNumber,
            pmCode: blocked.pmCode,
            reason: blocked.deferralReason,
          },
          `PM blocked: ${blocked.trainNumber} ${blocked.pmCode}`
        );
        await context.log(`- ${blocked.trainNumber} ${blocked.pmCode}: ${blocked.deferralReason ?? 'Unknown reason'}`);
      }

      if (result.blocked.length > 5) {
        await context.log(`... and ${result.blocked.length - 5} more blocked PMs`);
      }
    }

    // Record metrics for Prometheus
    span.setAttribute('scheduling.scheduled', scheduledCount);
    span.setAttribute('scheduling.deferred', deferredCount);
    span.setAttribute('scheduling.blocked', blockedCount);
    span.setAttribute('scheduling.materialWarnings', result.materialWarnings.length);

    // Broadcast scheduler completion via WebSocket
    // Uses optimizer message format for UI consistency
    await broadcastSchedulerComplete({
      jobId: id,
      status: blockedCount > 0 ? 'FEASIBLE' : 'OPTIMAL',
      solveTimeMs: 0, // Not tracked for tactical scheduler
      assignmentCount: scheduledCount,
      unassignedCount: blockedCount + deferredCount,
    });

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    return result;
  });
}

/**
 * Register the tactical scheduler worker
 */
export function registerTacticalSchedulerWorker(): void {
  log.info('Tactical scheduler worker processor available for registration');
}
